                subject_map[header] = row[i]
            else:
                subject_map[header] = ""

        # For each subject that has a non-empty value, create a new row
        for subject_header, value in subject_map.items():
            if value:
                new_row = [name, subject_header, value]
                result.append(new_row)

    return result

