            cell = row[0]
            # Check if cell matches the pattern "NameXXX" where XXX is a number
            match = re.match(r'^Name(\d+)$', cell)
            if match:
                group_id = match.group(1)
                # Extract all cells belonging to this group
                group_cells = []
                for r in table:
