    numeric_cols = []
    for col_idx in range(len(headers)):
        is_numeric = True
        for row in data:
            if col_idx < len(row):
                try:
                    int(row[col_idx])
                except ValueError:
                    is_numeric = False
                    break
        if is_numeric:
            numeric_cols.append(col_idx)

    # Group rows by the first column (ID)
    groups = defaultdict(list)
    for row in data:
        if row:
            groups[row[0]].append(row)

    result = []
    for group_id, group_rows in groups.items():
        # Sort group rows by the last column (count) in descending order
        group_rows.sort(key=lambda x: int(x[-1]) if x[-1].isdigit() else 0, reverse=True)

        # Take the top row from the group
        top_row = group_rows[0]

        # If the top row has a count of 1, keep it as is
        if top_row[-1] == '1':
            result.append(top_row)
        else:
            # If the count is greater than 1, split the row into multiple rows
            # Each new row will have the same values except the last column will be 1
            for _ in range(int(top_row[-1])):
                new_row = top_row[:-1] + ['1']
                result.append(new_row)

    return result

