    header_row = None
    for i, row in enumerate(table):
        if any(cell.strip() for cell in row):
            header_row = row
            break

    if header_row is None:
        return []

    # Determine column types based on header row
    # First column is likely an identifier (name)
    # Second column contains labels like "Tel:", "Fax:" which are categories
    # Subsequent columns are generated headers (values)

    # Extract column names from header row
    col_names = []
    for cell in header_row:
        if cell.strip():
            col_names.append(cell.strip())
        else:
            col_names.append("")

    # Identify which columns are categories (contain "Tel:", "Fax:", etc.)
    category_cols = []
    for i, name in enumerate(col_names):
        if name and (name.startswith("Tel:") or name.startswith("Fax:")):
            category_cols.append(i)

    # If no category columns found, assume first non-identifier column is category
    if not category_cols:
        for i in range(1, len(col_names)):
            if col_names[i]:
                category_cols.append(i)
                break

    # If still no category columns, assume second column is category
    if not category_cols and len(col_names) > 1:
        category_cols = [1]

    # Transform each row
    result = []
    for row in table:
