                # First column: identifier (name)
                new_row.append(cell.strip() if cell else "")
            elif i in category_cols:
                # Category column: extract label (e.g., "Tel" from "Tel:123")
                if cell:
                    label = cell.split(":")[0].strip()
                    new_row.append(label)
                else:
                    new_row.append("")
