        return []

    headers = table[0]
    data_rows = table[1:]

    # Identify column types based on header names
    # - "Header1", "Header2", etc. are likely identifiers (odd numbers)
    # - "Header3", "Header5", etc. are likely measures (even numbers)
    # - "Header2", "Header4", etc. are likely categories (even numbers)
    # - "Header1", "Header3", etc. are likely generated headers (odd numbers)

