    # - Odd-numbered headers (1, 3, 5...) are identifiers
    # - Even-numbered headers (2, 4, 6...) are categories
    # - Odd-numbered headers (1, 3, 5...) are also generated headers

    # We'll create a mapping of header names to their types
    header_types = {}
    for i, header in enumerate(headers):
        # Extract the number from the header name
        match = re.match(r'Header(\d+)', header)
        if match:
            num = int(match.group(1))
            if num % 2 == 1:
                header_types[header] = 'identifier'
            else:
                header_types[header] = 'category'
        else:
            header_types[header] = 'unknown'

    # Now, let's create the output table
    # We'll keep only the identifiers and generated headers
    output_headers = []
    for header in headers:
